import type { SATQuestion } from './types'

// SAT R&W Batch 7 - Vocabulary & Comprehension II (120 questions)
export const rwBatch7: SATQuestion[] = [
  { id: 'sat_rw_b7_001', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The morning dew on the grass was ________, vanishing completely by the time the sun reached its peak.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'ephemeral' }, { letter: 'B', text: 'perpetual' }, { letter: 'C', text: 'resilient' }, { letter: 'D', text: 'abundant' }], correct: 'A', explanation: '"Ephemeral" means lasting for a very short time, fitting something that vanishes quickly.' },
  { id: 'sat_rw_b7_002', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'Smartphones have become ________ in modern society; it is nearly impossible to find someone without one.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'ubiquitous' }, { letter: 'B', text: 'obsolete' }, { letter: 'C', text: 'scarce' }, { letter: 'D', text: 'controversial' }], correct: 'A', explanation: '"Ubiquitous" means found everywhere, which fits the idea that nearly everyone has a smartphone.' },
  { id: 'sat_rw_b7_003', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'Rather than pursuing an idealistic vision, the mayor took a ________ approach, focusing on achievable goals within the budget.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'pragmatic' }, { letter: 'B', text: 'reckless' }, { letter: 'C', text: 'theoretical' }, { letter: 'D', text: 'extravagant' }], correct: 'A', explanation: '"Pragmatic" means dealing with things in a practical way, matching the focus on achievable goals.' },
  { id: 'sat_rw_b7_004', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The new tutoring program was designed to ________ the struggles of students who were falling behind in mathematics.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'ameliorate' }, { letter: 'B', text: 'exacerbate' }, { letter: 'C', text: 'disregard' }, { letter: 'D', text: 'fabricate' }], correct: 'A', explanation: '"Ameliorate" means to make something bad better, fitting a program designed to help struggling students.' },
  { id: 'sat_rw_b7_005', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The politician\'s speech was filled with jargon that seemed intended to ________ the real issues rather than address them directly.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'obfuscate' }, { letter: 'B', text: 'illuminate' }, { letter: 'C', text: 'celebrate' }, { letter: 'D', text: 'simplify' }], correct: 'A', explanation: '"Obfuscate" means to make unclear or obscure, fitting the idea of hiding real issues with jargon.' },
  { id: 'sat_rw_b7_006', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'Known for being extremely ________, the talk show host could fill any awkward silence with effortless conversation.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'loquacious' }, { letter: 'B', text: 'reticent' }, { letter: 'C', text: 'hostile' }, { letter: 'D', text: 'negligent' }], correct: 'A', explanation: '"Loquacious" means very talkative, fitting someone who can fill silences with conversation.' },
  { id: 'sat_rw_b7_007', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'Despite the team\'s recent losses, the coach remained ________, expressing confidence that they would win the championship.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'sanguine' }, { letter: 'B', text: 'despondent' }, { letter: 'C', text: 'indifferent' }, { letter: 'D', text: 'vindictive' }], correct: 'A', explanation: '"Sanguine" means optimistic or positive, matching the coach\'s confidence despite losses.' },
  { id: 'sat_rw_b7_008', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The employee\'s ________ greeting suggested she was merely going through the motions rather than genuinely welcoming customers.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'perfunctory' }, { letter: 'B', text: 'enthusiastic' }, { letter: 'C', text: 'elaborate' }, { letter: 'D', text: 'sincere' }], correct: 'A', explanation: '"Perfunctory" means done without care or interest, fitting someone going through the motions.' },
  { id: 'sat_rw_b7_009', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The scientist\'s findings were ________, providing strong evidence that supported the original hypothesis.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'compelling' }, { letter: 'B', text: 'dubious' }, { letter: 'C', text: 'trivial' }, { letter: 'D', text: 'ambiguous' }], correct: 'A', explanation: '"Compelling" means convincing and persuasive, fitting findings that provide strong evidence.' },
  { id: 'sat_rw_b7_010', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The charity\'s mission was entirely ________, focused on helping others without expecting anything in return.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'altruistic' }, { letter: 'B', text: 'selfish' }, { letter: 'C', text: 'lucrative' }, { letter: 'D', text: 'punitive' }], correct: 'A', explanation: '"Altruistic" means selflessly concerned for the well-being of others.' },
  { id: 'sat_rw_b7_011', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The directions were so ________ that even someone unfamiliar with the area could easily find the location.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'lucid' }, { letter: 'B', text: 'convoluted' }, { letter: 'C', text: 'cryptic' }, { letter: 'D', text: 'verbose' }], correct: 'A', explanation: '"Lucid" means clear and easy to understand, fitting directions that anyone can follow.' },
  { id: 'sat_rw_b7_012', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The professor\'s ________ lecture style kept students engaged, as she wove humor and real-world examples into every lesson.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'dynamic' }, { letter: 'B', text: 'monotonous' }, { letter: 'C', text: 'rigid' }, { letter: 'D', text: 'austere' }], correct: 'A', explanation: '"Dynamic" means energetic and stimulating, fitting a lecture style that keeps students engaged.' },
  { id: 'sat_rw_b7_013', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The old building had fallen into a state of ________, with crumbling walls and overgrown weeds surrounding it.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'dilapidation' }, { letter: 'B', text: 'renovation' }, { letter: 'C', text: 'prosperity' }, { letter: 'D', text: 'elegance' }], correct: 'A', explanation: '"Dilapidation" means a state of disrepair, matching the description of crumbling walls and weeds.' },
  { id: 'sat_rw_b7_014', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The diplomat was known for her ________ manner, always choosing words carefully to avoid offending anyone.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'tactful' }, { letter: 'B', text: 'blunt' }, { letter: 'C', text: 'aggressive' }, { letter: 'D', text: 'apathetic' }], correct: 'A', explanation: '"Tactful" means showing sensitivity in dealing with others, fitting a careful diplomat.' },
  { id: 'sat_rw_b7_015', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The evidence against the defendant was ________, leaving the jury with no reasonable doubt about the verdict.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'irrefutable' }, { letter: 'B', text: 'questionable' }, { letter: 'C', text: 'circumstantial' }, { letter: 'D', text: 'negligible' }], correct: 'A', explanation: '"Irrefutable" means impossible to deny or disprove, matching evidence that leaves no reasonable doubt.' },
  { id: 'sat_rw_b7_016', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Photosynthesis is the process by which green plants convert sunlight into chemical energy. During this process, plants absorb carbon dioxide from the atmosphere and release oxygen as a byproduct. This exchange of gases is essential for maintaining breathable air on Earth.', question: 'Which choice best states the main idea of the passage?', options: [{ letter: 'A', text: 'Photosynthesis allows plants to produce energy from sunlight while contributing to Earth\'s oxygen supply.' }, { letter: 'B', text: 'Plants are the only organisms capable of converting energy from the sun.' }, { letter: 'C', text: 'Carbon dioxide is harmful to the atmosphere and must be removed by plants.' }, { letter: 'D', text: 'The exchange of gases during photosynthesis is a recent scientific discovery.' }], correct: 'A', explanation: 'The passage describes photosynthesis as both an energy conversion process and a contributor to atmospheric oxygen.' },
  { id: 'sat_rw_b7_017', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'In 1920, the Nineteenth Amendment to the United States Constitution was ratified, granting women the right to vote. This victory came after decades of activism by suffragists who organized marches, wrote petitions, and endured imprisonment. The amendment marked a turning point in the broader struggle for equal rights.', question: 'Based on the passage, which statement best describes the significance of the Nineteenth Amendment?', options: [{ letter: 'A', text: 'It represented a major achievement in the long fight for women\'s equality in the United States.' }, { letter: 'B', text: 'It was passed quickly and with little opposition from the government.' }, { letter: 'C', text: 'It ended all forms of discrimination against women in the United States.' }, { letter: 'D', text: 'It was primarily the result of a single organized protest march.' }], correct: 'A', explanation: 'The passage emphasizes decades of activism and calls it a "turning point," indicating a major achievement in the equality struggle.' },
  { id: 'sat_rw_b7_018', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'The placebo effect occurs when patients experience real improvements in their condition after receiving a treatment with no active ingredients. Researchers believe this happens because the brain releases chemicals associated with healing when a person believes they are being treated. The effect demonstrates the powerful connection between mind and body.', question: 'What is the author\'s primary purpose in this passage?', options: [{ letter: 'A', text: 'To explain what the placebo effect is and why it occurs' }, { letter: 'B', text: 'To argue that placebos should replace conventional medicine' }, { letter: 'C', text: 'To criticize researchers who study the placebo effect' }, { letter: 'D', text: 'To prove that all medical treatments are essentially placebos' }], correct: 'A', explanation: 'The passage defines the placebo effect and offers a scientific explanation for why it happens.' },
  { id: 'sat_rw_b7_019', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Coral reefs support roughly 25 percent of all marine species despite covering less than one percent of the ocean floor. These underwater ecosystems provide food and shelter for fish, invertebrates, and algae. However, rising ocean temperatures and pollution threaten to destroy many of the world\'s coral reefs within the coming decades.', question: 'Which choice best describes the structure of the passage?', options: [{ letter: 'A', text: 'It presents the importance of coral reefs and then identifies threats to their survival.' }, { letter: 'B', text: 'It argues that coral reefs are not as important as scientists believe.' }, { letter: 'C', text: 'It compares coral reefs to other types of marine ecosystems.' }, { letter: 'D', text: 'It proposes specific solutions for protecting coral reefs from destruction.' }], correct: 'A', explanation: 'The passage first establishes the ecological importance of coral reefs, then shifts to discuss the threats they face.' },
  { id: 'sat_rw_b7_020', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'During the Great Migration of the early twentieth century, millions of African Americans moved from the rural South to cities in the North and West. They sought better economic opportunities and an escape from the oppressive Jim Crow laws. This mass relocation reshaped American culture, contributing to the Harlem Renaissance and other cultural movements.', question: 'It can be inferred from the passage that the Great Migration was motivated primarily by:', options: [{ letter: 'A', text: 'a desire for improved living conditions and freedom from racial discrimination' }, { letter: 'B', text: 'government programs that encouraged relocation to northern cities' }, { letter: 'C', text: 'a shortage of labor in southern agricultural industries' }, { letter: 'D', text: 'the influence of the Harlem Renaissance on southern communities' }], correct: 'A', explanation: 'The passage states migrants sought "better economic opportunities" and escape from "oppressive Jim Crow laws."' },
  { id: 'sat_rw_b7_021', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'After months of negotiation, the two countries reached a ________ agreement that satisfied both parties.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'bilateral' }, { letter: 'B', text: 'unilateral' }, { letter: 'C', text: 'hostile' }, { letter: 'D', text: 'ambivalent' }], correct: 'A', explanation: '"Bilateral" means involving two parties, fitting an agreement between two countries.' },
  { id: 'sat_rw_b7_022', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The author\'s writing style is remarkably ________, conveying complex ideas in simple, accessible language.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'succinct' }, { letter: 'B', text: 'verbose' }, { letter: 'C', text: 'ornate' }, { letter: 'D', text: 'archaic' }], correct: 'A', explanation: '"Succinct" means briefly and clearly expressed, fitting writing that conveys complex ideas simply.' },
  { id: 'sat_rw_b7_023', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The medicine had a ________ effect on the patient\'s symptoms, providing relief almost immediately after being administered.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'salutary' }, { letter: 'B', text: 'detrimental' }, { letter: 'C', text: 'negligible' }, { letter: 'D', text: 'delayed' }], correct: 'A', explanation: '"Salutary" means producing a beneficial effect, matching the immediate relief described.' },
  { id: 'sat_rw_b7_024', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The critic\'s review was ________, harshly condemning every aspect of the film from the script to the acting.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'scathing' }, { letter: 'B', text: 'laudatory' }, { letter: 'C', text: 'impartial' }, { letter: 'D', text: 'superficial' }], correct: 'A', explanation: '"Scathing" means severely critical, fitting a review that harshly condemns a film.' },
  { id: 'sat_rw_b7_025', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The volunteers worked with great ________, showing passionate dedication to rebuilding homes destroyed by the hurricane.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'fervor' }, { letter: 'B', text: 'reluctance' }, { letter: 'C', text: 'apathy' }, { letter: 'D', text: 'hesitation' }], correct: 'A', explanation: '"Fervor" means intense and passionate feeling, matching the volunteers\' dedicated work.' },
  { id: 'sat_rw_b7_026', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Supply and demand is a fundamental concept in economics. When the supply of a good exceeds demand, prices tend to fall. Conversely, when demand outpaces supply, prices rise. This dynamic helps explain why the cost of seasonal produce fluctuates throughout the year.', question: 'The author mentions seasonal produce primarily to:', options: [{ letter: 'A', text: 'provide a concrete example of how supply and demand affect prices' }, { letter: 'B', text: 'argue that food prices are unfairly high during certain seasons' }, { letter: 'C', text: 'suggest that consumers should only buy produce when it is in season' }, { letter: 'D', text: 'demonstrate that supply and demand does not apply to all goods' }], correct: 'A', explanation: 'Seasonal produce serves as a real-world illustration of the supply-and-demand principle described.' },
  { id: 'sat_rw_b7_027', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Jane Goodall began studying chimpanzees in Tanzania in 1960. Her patient observation methods revealed that chimps use tools, form social bonds, and display emotions previously thought to be uniquely human. Goodall\'s work fundamentally changed how scientists understand the relationship between humans and other primates.', question: 'According to the passage, Goodall\'s research was significant because it:', options: [{ letter: 'A', text: 'showed that chimpanzees share behavioral traits once believed to be exclusive to humans' }, { letter: 'B', text: 'proved that chimpanzees are more intelligent than all other animal species' }, { letter: 'C', text: 'led to the immediate protection of chimpanzee habitats worldwide' }, { letter: 'D', text: 'was the first scientific study ever conducted on animal behavior' }], correct: 'A', explanation: 'The passage states Goodall revealed chimps display behaviors "previously thought to be uniquely human."' },
  { id: 'sat_rw_b7_028', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The teacher\'s patience seemed ________, as she calmly answered the same question for the tenth time without any sign of frustration.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'inexhaustible' }, { letter: 'B', text: 'limited' }, { letter: 'C', text: 'feigned' }, { letter: 'D', text: 'sporadic' }], correct: 'A', explanation: '"Inexhaustible" means seemingly unlimited, fitting patience that shows no sign of running out.' },
  { id: 'sat_rw_b7_029', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The two theories, though developed independently, arrived at remarkably ________ conclusions about the origins of the universe.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'convergent' }, { letter: 'B', text: 'contradictory' }, { letter: 'C', text: 'irrelevant' }, { letter: 'D', text: 'superficial' }], correct: 'A', explanation: '"Convergent" means coming together or reaching the same point, fitting independent theories with similar conclusions.' },
  { id: 'sat_rw_b7_030', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The hiker felt a deep sense of ________ as she stood alone on the mountaintop, watching the sunrise over the vast landscape below.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'serenity' }, { letter: 'B', text: 'anxiety' }, { letter: 'C', text: 'resentment' }, { letter: 'D', text: 'boredom' }], correct: 'A', explanation: '"Serenity" means a state of calm and peace, fitting the tranquil mountaintop scene described.' },
  { id: 'sat_rw_b7_031', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Researchers studying sleep patterns have found that teenagers naturally tend to fall asleep later and wake up later than adults. This biological shift, driven by changes in melatonin production during puberty, conflicts with early school start times. Some districts have responded by pushing back the start of the school day.', question: 'Which choice best summarizes the central problem described in the passage?', options: [{ letter: 'A', text: 'Teenagers\' natural sleep schedules are misaligned with traditional school start times.' }, { letter: 'B', text: 'Schools refuse to adjust their schedules despite scientific evidence about sleep.' }, { letter: 'C', text: 'Melatonin production decreases significantly during puberty.' }, { letter: 'D', text: 'Adults and teenagers have identical sleep needs but different schedules.' }], correct: 'A', explanation: 'The passage identifies a conflict between teens\' biology-driven sleep patterns and early school schedules.' },
  { id: 'sat_rw_b7_032', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'The Library of Alexandria, founded in the third century BCE, was one of the largest and most significant libraries of the ancient world. It housed hundreds of thousands of scrolls and attracted scholars from across the Mediterranean. Though the exact circumstances of its destruction remain debated, its loss is widely regarded as a tragedy for human knowledge.', question: 'The passage characterizes the Library of Alexandria primarily as:', options: [{ letter: 'A', text: 'a major center of learning whose destruction represented a significant loss' }, { letter: 'B', text: 'a small collection of scrolls with limited scholarly importance' }, { letter: 'C', text: 'a library whose destruction has been fully explained by historians' }, { letter: 'D', text: 'an institution that only served scholars from Alexandria' }], correct: 'A', explanation: 'The passage emphasizes the library\'s significance and describes its loss as "a tragedy for human knowledge."' },
  { id: 'sat_rw_b7_033', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The artist\'s early works were ________, imitating the styles of famous painters, but her later pieces showed genuine originality.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'derivative' }, { letter: 'B', text: 'innovative' }, { letter: 'C', text: 'controversial' }, { letter: 'D', text: 'meticulous' }], correct: 'A', explanation: '"Derivative" means imitative of someone else\'s work, contrasting with the later "genuine originality."' },
  { id: 'sat_rw_b7_034', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The speaker\'s arguments were so ________ that even those who initially disagreed found themselves nodding in agreement.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'persuasive' }, { letter: 'B', text: 'incoherent' }, { letter: 'C', text: 'divisive' }, { letter: 'D', text: 'predictable' }], correct: 'A', explanation: '"Persuasive" means convincing, fitting arguments that change people\'s minds.' },
  { id: 'sat_rw_b7_035', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The novelist was known for her ________ descriptions of rural landscapes, painting vivid pictures with words that transported readers to the countryside.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'evocative' }, { letter: 'B', text: 'vague' }, { letter: 'C', text: 'technical' }, { letter: 'D', text: 'redundant' }], correct: 'A', explanation: '"Evocative" means bringing strong images or feelings to mind, fitting descriptions that transport readers.' },
  { id: 'sat_rw_b7_036', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'Bees play a critical role in agriculture by pollinating crops such as almonds, apples, and blueberries. Without bee pollination, many of these crops would produce significantly lower yields. Recent declines in bee populations have therefore raised concerns among farmers and environmental scientists alike.', question: 'Which choice best describes the relationship between the ideas in the passage?', options: [{ letter: 'A', text: 'Bees are essential to crop production, so declining bee populations threaten agricultural output.' }, { letter: 'B', text: 'Farmers are solely responsible for the decline in bee populations.' }, { letter: 'C', text: 'Bee populations have increased thanks to new agricultural techniques.' }, { letter: 'D', text: 'Environmental scientists disagree with farmers about the importance of bees.' }], correct: 'A', explanation: 'The passage links bees\' role in pollination to concern about declining populations and their impact on agriculture.' },
  { id: 'sat_rw_b7_037', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'Despite the CEO\'s attempts to project an image of transparency, many employees viewed the corporate restructuring as ________, carried out in secret without input from staff.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'clandestine' }, { letter: 'B', text: 'transparent' }, { letter: 'C', text: 'collaborative' }, { letter: 'D', text: 'mundane' }], correct: 'A', explanation: '"Clandestine" means done secretly, contrasting with the CEO\'s claim of transparency.' },
  { id: 'sat_rw_b7_038', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The professor\'s feedback was always ________, offering specific suggestions for improvement rather than vague praise.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'constructive' }, { letter: 'B', text: 'dismissive' }, { letter: 'C', text: 'arbitrary' }, { letter: 'D', text: 'generic' }], correct: 'A', explanation: '"Constructive" means serving a useful purpose and offering helpful suggestions for improvement.' },
  { id: 'sat_rw_b7_039', category: 'reading', subcategory: 'vocabulary', difficulty: 'easy', passage: 'The detective found the suspect\'s alibi to be ________, as multiple witnesses confirmed the story matched the facts.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'credible' }, { letter: 'B', text: 'implausible' }, { letter: 'C', text: 'fabricated' }, { letter: 'D', text: 'irrelevant' }], correct: 'A', explanation: '"Credible" means believable and convincing, fitting an alibi confirmed by multiple witnesses.' },
  { id: 'sat_rw_b7_040', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'easy', passage: 'The Industrial Revolution brought about massive changes in manufacturing and transportation during the eighteenth and nineteenth centuries. Factories replaced small workshops, and steam-powered machines dramatically increased production capacity. While these changes drove economic growth, they also led to overcrowded cities and poor working conditions for many laborers.', question: 'The author\'s tone toward the Industrial Revolution can best be described as:', options: [{ letter: 'A', text: 'balanced, acknowledging both its benefits and its drawbacks' }, { letter: 'B', text: 'entirely critical, focusing only on the negative consequences' }, { letter: 'C', text: 'enthusiastically supportive of all industrial changes' }, { letter: 'D', text: 'indifferent to the effects of industrialization on society' }], correct: 'A', explanation: 'The passage mentions economic growth (positive) and overcrowded cities and poor conditions (negative), showing a balanced perspective.' },
  { id: 'sat_rw_b7_041', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The researcher\'s ________ approach to data collection ensured that every variable was accounted for and every measurement was precise.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'meticulous' }, { letter: 'B', text: 'haphazard' }, { letter: 'C', text: 'superficial' }, { letter: 'D', text: 'expedient' }], correct: 'A', explanation: '"Meticulous" means showing great attention to detail, fitting the precise data collection described.' },
  { id: 'sat_rw_b7_042', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The philosopher argued that true happiness is not found in material wealth but in the ________ pleasures of intellectual pursuit and meaningful relationships.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'intangible' }, { letter: 'B', text: 'monetary' }, { letter: 'C', text: 'fleeting' }, { letter: 'D', text: 'ostentatious' }], correct: 'A', explanation: '"Intangible" means not able to be touched or measured physically, contrasting with "material wealth."' },
  { id: 'sat_rw_b7_043', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'Once considered a ________ figure in the literary world, the poet has recently gained recognition as one of the most important voices of her generation.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'marginal' }, { letter: 'B', text: 'dominant' }, { letter: 'C', text: 'celebrated' }, { letter: 'D', text: 'prolific' }], correct: 'A', explanation: '"Marginal" means not central or important, contrasting with the recent recognition described.' },
  { id: 'sat_rw_b7_044', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The committee\'s report was deliberately ________, avoiding specific recommendations and instead offering only general observations about the problem.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'equivocal' }, { letter: 'B', text: 'definitive' }, { letter: 'C', text: 'provocative' }, { letter: 'D', text: 'exhaustive' }], correct: 'A', explanation: '"Equivocal" means open to more than one interpretation or deliberately vague, matching the avoidance of specifics.' },
  { id: 'sat_rw_b7_045', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The city council\'s decision to demolish the historic theater was met with ________ opposition from residents who valued the building\'s cultural significance.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'vehement' }, { letter: 'B', text: 'tepid' }, { letter: 'C', text: 'sporadic' }, { letter: 'D', text: 'ambivalent' }], correct: 'A', explanation: '"Vehement" means showing strong feeling or passionate intensity, fitting fierce opposition.' },
  { id: 'sat_rw_b7_046', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The journalist\'s investigation revealed that the company had engaged in ________ business practices, deceiving customers about the quality of its products.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'fraudulent' }, { letter: 'B', text: 'exemplary' }, { letter: 'C', text: 'benevolent' }, { letter: 'D', text: 'conventional' }], correct: 'A', explanation: '"Fraudulent" means obtained through deception, fitting practices that deceive customers.' },
  { id: 'sat_rw_b7_047', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'Although the politician claimed to be a champion of environmental causes, her voting record told a different story, revealing a ________ between her words and actions.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'discrepancy' }, { letter: 'B', text: 'harmony' }, { letter: 'C', text: 'correlation' }, { letter: 'D', text: 'redundancy' }], correct: 'A', explanation: '"Discrepancy" means a lack of compatibility between two things, fitting the gap between words and actions.' },
  { id: 'sat_rw_b7_048', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The new employee\'s ________ attitude impressed her supervisors; she consistently went beyond what was required and sought additional responsibilities.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'assiduous' }, { letter: 'B', text: 'complacent' }, { letter: 'C', text: 'indolent' }, { letter: 'D', text: 'defiant' }], correct: 'A', explanation: '"Assiduous" means showing great care and perseverance, fitting someone who goes beyond requirements.' },
  { id: 'sat_rw_b7_049', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The historian cautioned against viewing past events through a ________ lens, arguing that modern values should not be imposed on historical figures who lived in vastly different contexts.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'presentist' }, { letter: 'B', text: 'nostalgic' }, { letter: 'C', text: 'objective' }, { letter: 'D', text: 'complimentary' }], correct: 'A', explanation: '"Presentist" refers to judging the past by present-day standards, which the historian warns against.' },
  { id: 'sat_rw_b7_050', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The orchestra\'s performance was ________, with each musician playing in perfect synchronization and the conductor guiding them through every nuance of the piece.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'impeccable' }, { letter: 'B', text: 'mediocre' }, { letter: 'C', text: 'dissonant' }, { letter: 'D', text: 'unremarkable' }], correct: 'A', explanation: '"Impeccable" means flawless, fitting a performance with perfect synchronization.' },
  { id: 'sat_rw_b7_051', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Studies in behavioral economics have shown that people are more motivated by the fear of losing something than by the prospect of gaining something of equal value. This phenomenon, known as loss aversion, helps explain why investors often hold onto declining stocks rather than sell them at a loss. It also explains why free trial offers are so effective: once people have something, they are reluctant to give it up.', question: 'Based on the passage, which scenario best illustrates loss aversion?', options: [{ letter: 'A', text: 'A homeowner refuses to sell a house at a loss even though the market is unlikely to recover soon.' }, { letter: 'B', text: 'A shopper buys a product because it is offered at a steep discount.' }, { letter: 'C', text: 'An investor purchases stocks in a new company because of its growth potential.' }, { letter: 'D', text: 'A student studies harder after receiving a scholarship to maintain good grades.' }], correct: 'A', explanation: 'Refusing to sell at a loss directly demonstrates loss aversion, as the homeowner is motivated by fear of realizing a loss.' },
  { id: 'sat_rw_b7_052', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The discovery of penicillin by Alexander Fleming in 1928 is often described as a fortunate accident. Fleming noticed that a mold contaminating one of his bacterial cultures had killed the surrounding bacteria. However, historians note that Fleming\'s training in bacteriology and his habit of carefully observing his cultures were essential to recognizing the significance of what he saw. Chance alone did not produce the discovery.', question: 'The author\'s main argument in the passage is that:', options: [{ letter: 'A', text: 'Fleming\'s discovery of penicillin required both luck and scientific expertise.' }, { letter: 'B', text: 'Penicillin was discovered entirely through careful scientific planning.' }, { letter: 'C', text: 'Fleming\'s discovery was purely accidental and could have been made by anyone.' }, { letter: 'D', text: 'Modern historians have disproved the story of penicillin\'s accidental discovery.' }], correct: 'A', explanation: 'The passage acknowledges the role of chance but emphasizes that Fleming\'s expertise was also essential.' },
  { id: 'sat_rw_b7_053', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Sociologist Erving Goffman proposed that social life resembles a theatrical performance. According to his dramaturgical theory, people present different versions of themselves depending on the social context, much as actors play different roles on stage. Goffman called the public persona the "front stage" and the private, unguarded self the "backstage." His framework has been influential in understanding how individuals manage impressions in everyday interactions.', question: 'Which choice best describes the function of the theatrical metaphor in the passage?', options: [{ letter: 'A', text: 'It illustrates Goffman\'s theory that people adapt their behavior to fit different social situations.' }, { letter: 'B', text: 'It suggests that Goffman believed people are fundamentally dishonest.' }, { letter: 'C', text: 'It shows that sociology and theater are essentially the same discipline.' }, { letter: 'D', text: 'It criticizes people for not being authentic in their daily interactions.' }], correct: 'A', explanation: 'The theatrical metaphor serves to explain how people present different selves in different social contexts.' },
  { id: 'sat_rw_b7_054', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The novelist\'s latest work is ________, spanning three generations and multiple continents in its exploration of immigration and identity.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'sweeping' }, { letter: 'B', text: 'concise' }, { letter: 'C', text: 'provincial' }, { letter: 'D', text: 'understated' }], correct: 'A', explanation: '"Sweeping" means wide in range or effect, fitting a novel that spans generations and continents.' },
  { id: 'sat_rw_b7_055', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The professor was known for her ________ wit, delivering sharp and humorous remarks that kept her students both entertained and intellectually challenged.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'sardonic' }, { letter: 'B', text: 'benign' }, { letter: 'C', text: 'ponderous' }, { letter: 'D', text: 'banal' }], correct: 'A', explanation: '"Sardonic" means grimly mocking or cynically humorous, fitting sharp and clever remarks.' },
  { id: 'sat_rw_b7_056', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The documentary filmmaker sought to present a ________ account of the conflict, interviewing people on both sides and letting viewers draw their own conclusions.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'dispassionate' }, { letter: 'B', text: 'partisan' }, { letter: 'C', text: 'sensational' }, { letter: 'D', text: 'inflammatory' }], correct: 'A', explanation: '"Dispassionate" means not influenced by strong emotion, fitting an objective approach to a conflict.' },
  { id: 'sat_rw_b7_057', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The CEO\'s abrupt resignation sent ________ through the company, with employees scrambling to understand what it meant for the organization\'s future.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'shockwaves' }, { letter: 'B', text: 'relief' }, { letter: 'C', text: 'indifference' }, { letter: 'D', text: 'celebration' }], correct: 'A', explanation: '"Shockwaves" conveys sudden, widespread impact, fitting the disruption caused by an abrupt resignation.' },
  { id: 'sat_rw_b7_058', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The young composer\'s symphony was praised for its ________ blend of classical structure and modern jazz harmonies, creating something entirely new.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'ingenious' }, { letter: 'B', text: 'conventional' }, { letter: 'C', text: 'discordant' }, { letter: 'D', text: 'predictable' }], correct: 'A', explanation: '"Ingenious" means clever and inventive, fitting an innovative blend of musical styles.' },
  { id: 'sat_rw_b7_059', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The concept of neuroplasticity has transformed our understanding of the brain. Once thought to be fixed after childhood, the brain is now known to reorganize itself by forming new neural connections throughout life. This discovery has significant implications for rehabilitation after brain injuries, suggesting that damaged areas can sometimes be compensated for by other regions of the brain.', question: 'Which choice best states the main idea of the passage?', options: [{ letter: 'A', text: 'The brain\'s ability to form new connections throughout life has changed scientific understanding and offers hope for injury recovery.' }, { letter: 'B', text: 'Brain injuries are now fully treatable thanks to the discovery of neuroplasticity.' }, { letter: 'C', text: 'Scientists have always known that the brain continues to develop after childhood.' }, { letter: 'D', text: 'Neuroplasticity is a theory that has been widely rejected by modern neuroscientists.' }], correct: 'A', explanation: 'The passage describes how neuroplasticity changed scientific understanding and its implications for brain injury rehabilitation.' },
  { id: 'sat_rw_b7_060', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'In her 1962 book Silent Spring, Rachel Carson documented the harmful effects of pesticides on wildlife and the environment. Chemical companies attacked her findings, but subsequent research confirmed her warnings. The book is widely credited with launching the modern environmental movement and led to the eventual ban of the pesticide DDT in the United States.', question: 'The passage suggests that chemical companies\' response to Silent Spring was:', options: [{ letter: 'A', text: 'hostile, though Carson\'s claims were later validated by further research' }, { letter: 'B', text: 'supportive, leading to voluntary reductions in pesticide use' }, { letter: 'C', text: 'indifferent, as they did not consider the book a serious threat' }, { letter: 'D', text: 'effective in discrediting Carson\'s work permanently' }], correct: 'A', explanation: 'The passage states companies "attacked her findings" but "subsequent research confirmed her warnings," showing their hostility was ultimately unsuccessful.' },
  { id: 'sat_rw_b7_061', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The defense attorney argued that the prosecution\'s case was built on ________ evidence, consisting of unverified reports and secondhand accounts rather than hard facts.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'tenuous' }, { letter: 'B', text: 'robust' }, { letter: 'C', text: 'conclusive' }, { letter: 'D', text: 'empirical' }], correct: 'A', explanation: '"Tenuous" means weak or slight, fitting evidence based on unverified reports and hearsay.' },
  { id: 'sat_rw_b7_062', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The once-thriving downtown district had become ________, with empty storefronts and deserted streets replacing what was once a bustling commercial center.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'moribund' }, { letter: 'B', text: 'vibrant' }, { letter: 'C', text: 'congested' }, { letter: 'D', text: 'affluent' }], correct: 'A', explanation: '"Moribund" means in a state of decline or near death, fitting the contrast with "once-thriving."' },
  { id: 'sat_rw_b7_063', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The diplomat\'s ability to find ________ in seemingly intractable disputes earned her a reputation as one of the most effective negotiators in the foreign service.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'consensus' }, { letter: 'B', text: 'discord' }, { letter: 'C', text: 'stagnation' }, { letter: 'D', text: 'controversy' }], correct: 'A', explanation: '"Consensus" means general agreement, fitting a negotiator who resolves difficult disputes.' },
  { id: 'sat_rw_b7_064', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Economists have long debated the relationship between income and happiness. While studies consistently show that people in wealthier nations report higher levels of life satisfaction, the correlation weakens significantly above a certain income threshold. This suggests that once basic needs are met, additional wealth has diminishing returns on subjective well-being.', question: 'Which statement is best supported by the passage?', options: [{ letter: 'A', text: 'Beyond a certain income level, earning more money contributes less to personal happiness.' }, { letter: 'B', text: 'Wealthy people are generally less happy than people with lower incomes.' }, { letter: 'C', text: 'There is no relationship between income and happiness at any level.' }, { letter: 'D', text: 'Economists have reached a consensus that money cannot buy happiness.' }], correct: 'A', explanation: 'The passage states the income-happiness correlation "weakens significantly above a certain threshold," indicating diminishing returns.' },
  { id: 'sat_rw_b7_065', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The Rosetta Stone, discovered in 1799 by French soldiers in Egypt, bears the same decree inscribed in three scripts: Greek, Demotic, and hieroglyphics. Because scholars could already read Greek, they used it as a key to decipher the long-mysterious Egyptian hieroglyphics. Jean-François Champollion finally cracked the code in 1822, opening up the study of ancient Egyptian civilization.', question: 'According to the passage, the Rosetta Stone was important primarily because it:', options: [{ letter: 'A', text: 'provided the means to translate Egyptian hieroglyphics using a known language' }, { letter: 'B', text: 'proved that Greek was the most widely spoken language in ancient Egypt' }, { letter: 'C', text: 'was the only surviving example of ancient Egyptian writing' }, { letter: 'D', text: 'revealed that Demotic script was a simplified version of Greek' }], correct: 'A', explanation: 'The passage explains that scholars used the Greek text as a key to decipher the hieroglyphics.' },
  { id: 'sat_rw_b7_066', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The ecologist warned that the introduction of an invasive species could ________ the delicate balance of the local ecosystem, potentially driving native species to extinction.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'disrupt' }, { letter: 'B', text: 'fortify' }, { letter: 'C', text: 'replicate' }, { letter: 'D', text: 'stabilize' }], correct: 'A', explanation: '"Disrupt" means to disturb or interfere with, fitting the threat to an ecosystem\'s balance.' },
  { id: 'sat_rw_b7_067', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The architect\'s design was praised for its ________ use of natural light, with strategically placed windows and skylights that reduced the need for artificial lighting.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'judicious' }, { letter: 'B', text: 'wasteful' }, { letter: 'C', text: 'negligible' }, { letter: 'D', text: 'arbitrary' }], correct: 'A', explanation: '"Judicious" means showing good judgment, fitting the strategic and praised use of natural light.' },
  { id: 'sat_rw_b7_068', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The scientist\'s hypothesis, once dismissed as ________ by her peers, was eventually confirmed by a landmark study published in a prestigious journal.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'speculative' }, { letter: 'B', text: 'definitive' }, { letter: 'C', text: 'orthodox' }, { letter: 'D', text: 'empirical' }], correct: 'A', explanation: '"Speculative" means based on conjecture rather than evidence, fitting a hypothesis initially dismissed but later confirmed.' },
  { id: 'sat_rw_b7_069', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Psychologist Carol Dweck\'s research distinguishes between two mindsets: a "fixed" mindset, in which people believe their abilities are innate and unchangeable, and a "growth" mindset, in which people believe abilities can be developed through effort. Dweck has found that students with a growth mindset tend to embrace challenges and persist through setbacks, while those with a fixed mindset often avoid difficult tasks for fear of failure.', question: 'Based on the passage, a student with a fixed mindset would most likely respond to a difficult math problem by:', options: [{ letter: 'A', text: 'giving up quickly, believing the problem is beyond their natural ability' }, { letter: 'B', text: 'working harder and seeking help to develop new problem-solving strategies' }, { letter: 'C', text: 'viewing the challenge as an opportunity to improve their skills' }, { letter: 'D', text: 'feeling motivated by the difficulty of the task' }], correct: 'A', explanation: 'The passage states that fixed-mindset individuals "avoid difficult tasks for fear of failure," so giving up aligns with this behavior.' },
  { id: 'sat_rw_b7_070', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The Tragedy of the Commons, a concept introduced by Garrett Hardin in 1968, describes a situation in which individuals acting in their own self-interest deplete a shared resource, ultimately harming everyone. Hardin used the example of herders overgrazing a common pasture. While each herder benefits individually from adding more animals, the collective effect is the destruction of the pasture for all. The concept has been applied to issues ranging from overfishing to climate change.', question: 'The passage indicates that the Tragedy of the Commons occurs because:', options: [{ letter: 'A', text: 'individual self-interest leads to the overuse of resources that are shared by a group' }, { letter: 'B', text: 'governments fail to regulate private property effectively' }, { letter: 'C', text: 'people are unaware that shared resources can be depleted' }, { letter: 'D', text: 'herders deliberately destroy pastures to prevent others from using them' }], correct: 'A', explanation: 'The passage defines the concept as individuals acting in self-interest depleting a shared resource, harming everyone.' },
  { id: 'sat_rw_b7_071', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The author\'s memoir is remarkable for its ________, presenting painful memories with honesty and directness rather than glossing over difficult experiences.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'candor' }, { letter: 'B', text: 'evasiveness' }, { letter: 'C', text: 'embellishment' }, { letter: 'D', text: 'sentimentality' }], correct: 'A', explanation: '"Candor" means the quality of being open and honest, fitting a memoir that presents painful memories directly.' },
  { id: 'sat_rw_b7_072', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The corporation\'s announcement of record profits seemed ________ given that it had simultaneously laid off thousands of workers.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'incongruous' }, { letter: 'B', text: 'appropriate' }, { letter: 'C', text: 'predictable' }, { letter: 'D', text: 'reassuring' }], correct: 'A', explanation: '"Incongruous" means not in harmony or out of place, fitting the contradiction between profits and layoffs.' },
  { id: 'sat_rw_b7_073', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The young activist\'s speech was ________, stirring the audience to action with its passionate call for social justice reform.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'galvanizing' }, { letter: 'B', text: 'soporific' }, { letter: 'C', text: 'divisive' }, { letter: 'D', text: 'pedestrian' }], correct: 'A', explanation: '"Galvanizing" means shocking or exciting someone into taking action, fitting a speech that stirred the audience.' },
  { id: 'sat_rw_b7_074', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Researchers studying the microbiome have discovered that the trillions of bacteria living in the human gut play a far more significant role in health than previously understood. These microorganisms help digest food, produce essential vitamins, and regulate the immune system. Emerging evidence even suggests a connection between gut bacteria and mental health, a relationship scientists call the "gut-brain axis."', question: 'The primary purpose of the passage is to:', options: [{ letter: 'A', text: 'describe the expanding understanding of gut bacteria\'s role in human health' }, { letter: 'B', text: 'argue that gut bacteria are more important than the brain for mental health' }, { letter: 'C', text: 'explain the process by which scientists discovered the microbiome' }, { letter: 'D', text: 'compare the gut-brain axis to other biological systems in the body' }], correct: 'A', explanation: 'The passage progressively describes how understanding of gut bacteria has expanded from digestion to immune function to mental health.' },
  { id: 'sat_rw_b7_075', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The senator\'s ________ stance on the issue frustrated both supporters and opponents, as she refused to commit to either side of the debate.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'noncommittal' }, { letter: 'B', text: 'resolute' }, { letter: 'C', text: 'radical' }, { letter: 'D', text: 'transparent' }], correct: 'A', explanation: '"Noncommittal" means not expressing an opinion or preference, fitting a refusal to commit to either side.' },
  { id: 'sat_rw_b7_076', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The widespread ________ of misinformation on social media has made it increasingly difficult for the public to distinguish between reliable news and fabricated stories.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'proliferation' }, { letter: 'B', text: 'suppression' }, { letter: 'C', text: 'scarcity' }, { letter: 'D', text: 'clarification' }], correct: 'A', explanation: '"Proliferation" means rapid increase or spread, fitting the widespread growth of misinformation.' },
  { id: 'sat_rw_b7_077', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The prisoner\'s dilemma is a famous thought experiment in game theory. Two suspects are arrested and interrogated separately. If both remain silent, they each receive a minor sentence. If one betrays the other while the other stays silent, the betrayer goes free while the silent one receives a severe sentence. If both betray each other, both receive moderate sentences. The dilemma illustrates why rational individuals might not cooperate even when it is in their mutual interest to do so.', question: 'According to the passage, the prisoner\'s dilemma demonstrates that:', options: [{ letter: 'A', text: 'rational self-interest can lead individuals to outcomes that are worse for everyone involved' }, { letter: 'B', text: 'cooperation between criminals always leads to the best possible outcome' }, { letter: 'C', text: 'betrayal is always the most logical strategy in any negotiation' }, { letter: 'D', text: 'game theory has no practical application outside of criminal justice' }], correct: 'A', explanation: 'The passage states the dilemma shows why rational individuals "might not cooperate even when it is in their mutual interest."' },
  { id: 'sat_rw_b7_078', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The editor found the manuscript to be ________, filled with unnecessary repetition and digressions that added nothing to the central argument.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'prolix' }, { letter: 'B', text: 'terse' }, { letter: 'C', text: 'riveting' }, { letter: 'D', text: 'polished' }], correct: 'A', explanation: '"Prolix" means using too many words or being tediously long, fitting a manuscript full of repetition and digressions.' },
  { id: 'sat_rw_b7_079', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The researcher\'s findings were ________, applying not only to the specific population studied but to broader demographics as well.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'generalizable' }, { letter: 'B', text: 'anomalous' }, { letter: 'C', text: 'localized' }, { letter: 'D', text: 'controversial' }], correct: 'A', explanation: '"Generalizable" means applicable to a wider group beyond the original sample, fitting findings with broad relevance.' },
  { id: 'sat_rw_b7_080', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'The Sapir-Whorf hypothesis proposes that the language a person speaks influences how they perceive and think about the world. In its strong form, the hypothesis suggests that language determines thought entirely. Most modern linguists favor a weaker version, arguing that language shapes habitual thought patterns without strictly limiting cognition. Research on color perception across cultures has provided some of the most compelling evidence for this weaker interpretation.', question: 'The passage suggests that most modern linguists believe:', options: [{ letter: 'A', text: 'language influences thought but does not completely determine it' }, { letter: 'B', text: 'language has no measurable effect on how people think' }, { letter: 'C', text: 'the strong form of the Sapir-Whorf hypothesis is correct' }, { letter: 'D', text: 'color perception is unrelated to language' }], correct: 'A', explanation: 'The passage states most linguists favor the "weaker version" in which language "shapes" thought without "strictly limiting" it.' },
  { id: 'sat_rw_b7_081', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The governor\'s proposed budget was a ________ measure, intended to address the immediate fiscal crisis rather than implement long-term economic reforms.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'stopgap' }, { letter: 'B', text: 'comprehensive' }, { letter: 'C', text: 'permanent' }, { letter: 'D', text: 'revolutionary' }], correct: 'A', explanation: '"Stopgap" means a temporary solution, fitting a measure addressing an immediate crisis rather than long-term reform.' },
  { id: 'sat_rw_b7_082', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The company\'s decision to enter the foreign market was ________ by years of careful research into consumer preferences and local regulations.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'preceded' }, { letter: 'B', text: 'undermined' }, { letter: 'C', text: 'contradicted' }, { letter: 'D', text: 'improvised' }], correct: 'A', explanation: '"Preceded" means came before, fitting the idea that research happened before the market entry decision.' },
  { id: 'sat_rw_b7_083', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'In a 2019 study, researchers found that trees in forests communicate through an underground network of fungi known as the "wood wide web." Through this network, trees can share nutrients, send chemical warning signals about insect attacks, and even support the growth of younger trees. The findings challenge the traditional view of forests as collections of competing individuals, suggesting instead that they function as cooperative communities.', question: 'The passage primarily serves to:', options: [{ letter: 'A', text: 'present evidence that trees cooperate through underground fungal networks, challenging earlier assumptions' }, { letter: 'B', text: 'argue that competition among trees is the primary driver of forest ecosystems' }, { letter: 'C', text: 'explain why fungi are harmful to forest environments' }, { letter: 'D', text: 'describe the process by which young trees grow faster than older trees' }], correct: 'A', explanation: 'The passage presents the fungal network as evidence of cooperation, explicitly noting it "challenges the traditional view" of competition.' },
  { id: 'sat_rw_b7_084', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The critic described the filmmaker\'s latest work as ________, noting that it borrowed heavily from earlier, more original films without adding anything new.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'unoriginal' }, { letter: 'B', text: 'groundbreaking' }, { letter: 'C', text: 'controversial' }, { letter: 'D', text: 'nuanced' }], correct: 'A', explanation: '"Unoriginal" means lacking novelty, fitting a film that borrows from earlier works "without adding anything new."' },
  { id: 'sat_rw_b7_085', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The teacher\'s ________ explanation of quantum mechanics made the subject accessible even to students with no background in physics.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'cogent' }, { letter: 'B', text: 'convoluted' }, { letter: 'C', text: 'esoteric' }, { letter: 'D', text: 'perfunctory' }], correct: 'A', explanation: '"Cogent" means clear, logical, and convincing, fitting an explanation that makes a difficult subject accessible.' },
  { id: 'sat_rw_b7_086', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Archaeologists studying ancient Mesopotamia have uncovered evidence suggesting that the city of Uruk, around 3500 BCE, may have been the world\'s first true city. With a population estimated at up to 80,000, Uruk featured monumental architecture, a complex bureaucracy, and one of the earliest known writing systems. Scholars believe these innovations arose in response to the challenges of managing such a large and dense population.', question: 'Based on the passage, the development of writing in Uruk was most likely driven by:', options: [{ letter: 'A', text: 'the administrative needs of governing a large urban population' }, { letter: 'B', text: 'a desire to record religious myths and literary texts' }, { letter: 'C', text: 'contact with other civilizations that already had writing systems' }, { letter: 'D', text: 'the artistic interests of Uruk\'s ruling class' }], correct: 'A', explanation: 'The passage states innovations including writing "arose in response to the challenges of managing" a large population.' },
  { id: 'sat_rw_b7_087', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The athlete\'s comeback after a career-threatening injury was nothing short of ________, defying the predictions of medical experts who said she would never compete again.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'remarkable' }, { letter: 'B', text: 'inevitable' }, { letter: 'C', text: 'modest' }, { letter: 'D', text: 'predictable' }], correct: 'A', explanation: '"Remarkable" means worthy of attention and extraordinary, fitting a comeback that defied medical predictions.' },
  { id: 'sat_rw_b7_088', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'medium', passage: 'Virginia Woolf\'s essay "A Room of One\'s Own" argues that women have been historically underrepresented in literature not because they lacked talent but because they lacked the material conditions necessary for creative work. Woolf contended that a woman needed financial independence and a private space in order to write fiction. Her argument extended beyond literature, highlighting how economic and social structures had limited women\'s intellectual contributions for centuries.', question: 'Woolf\'s central argument, as presented in the passage, is that:', options: [{ letter: 'A', text: 'women\'s underrepresentation in literature resulted from material and social constraints rather than a lack of ability' }, { letter: 'B', text: 'women are naturally better writers than men when given equal opportunities' }, { letter: 'C', text: 'financial independence is the only factor that determines literary success' }, { letter: 'D', text: 'women\'s contributions to literature have always been recognized equally' }], correct: 'A', explanation: 'The passage states women were underrepresented "not because they lacked talent but because they lacked the material conditions."' },
  { id: 'sat_rw_b7_089', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The CEO attempted to ________ concerns about the company\'s declining stock price by presenting an optimistic forecast for the next quarter.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'allay' }, { letter: 'B', text: 'amplify' }, { letter: 'C', text: 'validate' }, { letter: 'D', text: 'provoke' }], correct: 'A', explanation: '"Allay" means to reduce or diminish fears or concerns, fitting the CEO\'s attempt to ease worries.' },
  { id: 'sat_rw_b7_090', category: 'reading', subcategory: 'vocabulary', difficulty: 'medium', passage: 'The political commentator was known for her ________ analysis, cutting through rhetoric to identify the underlying motivations behind policy decisions.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'incisive' }, { letter: 'B', text: 'superficial' }, { letter: 'C', text: 'partisan' }, { letter: 'D', text: 'meandering' }], correct: 'A', explanation: '"Incisive" means showing clear thought and good understanding, fitting analysis that cuts through rhetoric.' },
  { id: 'sat_rw_b7_091', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The philosopher\'s treatise on ethics was notable for its ________ reasoning, building its arguments through a chain of tightly connected logical propositions that left little room for counterargument.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'rigorous' }, { letter: 'B', text: 'capricious' }, { letter: 'C', text: 'tangential' }, { letter: 'D', text: 'anecdotal' }], correct: 'A', explanation: '"Rigorous" means extremely thorough and careful, fitting tightly connected logical reasoning.' },
  { id: 'sat_rw_b7_092', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The anthropologist noted that the ritual, though appearing ________ to outsiders, held profound spiritual significance for the indigenous community that practiced it.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'arcane' }, { letter: 'B', text: 'transparent' }, { letter: 'C', text: 'frivolous' }, { letter: 'D', text: 'universal' }], correct: 'A', explanation: '"Arcane" means understood by few or mysterious, fitting a ritual that appears strange to outsiders but is meaningful to practitioners.' },
  { id: 'sat_rw_b7_093', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The literary critic argued that the novel\'s protagonist undergoes not a genuine transformation but merely a ________ change, adopting new behaviors without any fundamental shift in values or character.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'superficial' }, { letter: 'B', text: 'profound' }, { letter: 'C', text: 'irreversible' }, { letter: 'D', text: 'spontaneous' }], correct: 'A', explanation: '"Superficial" means existing only at the surface, fitting a change in behavior without deeper transformation.' },
  { id: 'sat_rw_b7_094', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The physicist\'s theory was initially met with ________ from the scientific establishment, as it challenged fundamental assumptions that had been accepted for decades.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'incredulity' }, { letter: 'B', text: 'acclaim' }, { letter: 'C', text: 'corroboration' }, { letter: 'D', text: 'indifference' }], correct: 'A', explanation: '"Incredulity" means disbelief, fitting the reaction to a theory that challenges long-held assumptions.' },
  { id: 'sat_rw_b7_095', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The geopolitical analyst described the region as a ________ of competing interests, where economic, religious, and ethnic tensions overlapped in ways that made conflict almost inevitable.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'nexus' }, { letter: 'B', text: 'vacuum' }, { letter: 'C', text: 'sanctuary' }, { letter: 'D', text: 'periphery' }], correct: 'A', explanation: '"Nexus" means a connection or series of connections linking things, fitting a convergence of competing interests.' },
  { id: 'sat_rw_b7_096', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The essayist\'s prose style is deliberately ________, employing fragmented sentences and abrupt shifts in tone to mirror the disorientation experienced by the subjects she writes about.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'disjointed' }, { letter: 'B', text: 'fluid' }, { letter: 'C', text: 'ornamental' }, { letter: 'D', text: 'formulaic' }], correct: 'A', explanation: '"Disjointed" means lacking coherent connection, fitting fragmented sentences used to convey disorientation.' },
  { id: 'sat_rw_b7_097', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Economist Thomas Piketty\'s analysis of wealth inequality argues that when the rate of return on capital exceeds the rate of economic growth, wealth concentrates increasingly among the already wealthy. This dynamic, Piketty contends, is not an aberration but a fundamental feature of capitalist economies. Critics, however, argue that Piketty underestimates the role of technological innovation in creating new wealth and disrupting existing fortunes.', question: 'The critics mentioned in the passage would most likely argue that:', options: [{ letter: 'A', text: 'technological innovation can counteract wealth concentration by generating new economic opportunities' }, { letter: 'B', text: 'wealth inequality is not a significant concern in modern economies' }, { letter: 'C', text: 'the rate of return on capital is always lower than the rate of economic growth' }, { letter: 'D', text: 'Piketty\'s data on historical wealth distribution is fabricated' }], correct: 'A', explanation: 'The critics argue Piketty underestimates innovation\'s role in "creating new wealth and disrupting existing fortunes."' },
  { id: 'sat_rw_b7_098', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Epigenetics, the study of heritable changes in gene expression that do not involve alterations to the DNA sequence itself, has complicated the traditional nature-versus-nurture debate. Research has shown that environmental factors such as diet, stress, and exposure to toxins can modify how genes are expressed, and some of these modifications can be passed to subsequent generations. This means that a parent\'s experiences may biologically influence their children\'s traits in ways that classical genetics could not explain.', question: 'The passage suggests that epigenetics is significant because it:', options: [{ letter: 'A', text: 'reveals that environmental influences can be inherited biologically, bridging the gap between nature and nurture' }, { letter: 'B', text: 'proves that DNA mutations are the primary cause of inherited diseases' }, { letter: 'C', text: 'demonstrates that environmental factors have no effect on gene expression' }, { letter: 'D', text: 'confirms the traditional view that genes alone determine an organism\'s traits' }], correct: 'A', explanation: 'The passage states environmental modifications can be inherited, which "complicated the traditional nature-versus-nurture debate" by connecting the two.' },
  { id: 'sat_rw_b7_099', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The diplomat navigated the negotiations with remarkable ________, knowing precisely when to press for concessions and when to offer compromises to maintain goodwill.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'acumen' }, { letter: 'B', text: 'naivete' }, { letter: 'C', text: 'obstinacy' }, { letter: 'D', text: 'impulsiveness' }], correct: 'A', explanation: '"Acumen" means the ability to make good judgments and quick decisions, fitting a diplomat\'s skilled negotiation.' },
  { id: 'sat_rw_b7_100', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The historian argued that the empire\'s collapse was not caused by a single catastrophic event but by the ________ erosion of its political institutions over several centuries.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'gradual' }, { letter: 'B', text: 'instantaneous' }, { letter: 'C', text: 'deliberate' }, { letter: 'D', text: 'artificial' }], correct: 'A', explanation: '"Gradual" means happening slowly over time, fitting erosion over "several centuries" contrasted with a single catastrophic event.' },
  { id: 'sat_rw_b7_101', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Hannah Arendt\'s concept of the "banality of evil," developed after observing the trial of Nazi official Adolf Eichmann, suggests that great moral crimes can be committed by ordinary people who fail to think critically about the consequences of their actions. Arendt argued that Eichmann was not a fanatical ideologue but a bureaucrat who unthinkingly followed orders. Her interpretation proved controversial, as many felt it minimized the horror of the Holocaust by portraying its perpetrators as mundane functionaries rather than monsters.', question: 'The controversy surrounding Arendt\'s concept arose primarily because:', options: [{ letter: 'A', text: 'her characterization of perpetrators as ordinary bureaucrats was seen as diminishing the gravity of their crimes' }, { letter: 'B', text: 'she argued that Eichmann was a fanatical ideologue who acted with full awareness' }, { letter: 'C', text: 'her theory was based on insufficient evidence from the trial' }, { letter: 'D', text: 'she claimed that all bureaucrats are capable of committing atrocities' }], correct: 'A', explanation: 'The passage states critics felt the concept "minimized the horror" by portraying perpetrators as "mundane functionaries."' },
  { id: 'sat_rw_b7_102', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The biographer strove for ________ in her portrayal of the controversial political leader, acknowledging both his significant policy achievements and his well-documented personal failings.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'equanimity' }, { letter: 'B', text: 'adulation' }, { letter: 'C', text: 'condemnation' }, { letter: 'D', text: 'exaggeration' }], correct: 'A', explanation: '"Equanimity" means mental calmness and composure, fitting a balanced portrayal that acknowledges both positives and negatives.' },
  { id: 'sat_rw_b7_103', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The senator\'s former allies accused her of ________ after she reversed her position on the tax bill, suggesting that her change of heart was motivated by political expediency rather than genuine conviction.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'duplicity' }, { letter: 'B', text: 'integrity' }, { letter: 'C', text: 'candor' }, { letter: 'D', text: 'prudence' }], correct: 'A', explanation: '"Duplicity" means deceitfulness or double-dealing, fitting accusations of an insincere reversal motivated by political gain.' },
  { id: 'sat_rw_b7_104', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The bystander effect, first identified by psychologists John Darley and Bibb Latané, describes the phenomenon in which individuals are less likely to offer help in an emergency when other people are present. The researchers proposed that the effect is driven by two factors: diffusion of responsibility, in which each person assumes someone else will act, and pluralistic ignorance, in which individuals look to others for cues and, seeing no one react, conclude the situation is not serious. Subsequent studies have shown that the effect is strongest in ambiguous situations and weakest when the emergency is clearly life-threatening.', question: 'Based on the passage, the bystander effect would most likely be weakest in which scenario?', options: [{ letter: 'A', text: 'A person collapses and stops breathing in a crowded shopping mall.' }, { letter: 'B', text: 'A stranger drops papers on a busy sidewalk during rush hour.' }, { letter: 'C', text: 'A car alarm goes off in a parking lot with several people nearby.' }, { letter: 'D', text: 'A person sits on a bench looking unwell in a park with many visitors.' }], correct: 'A', explanation: 'The passage states the effect is "weakest when the emergency is clearly life-threatening," and someone collapsing and not breathing is unambiguously life-threatening.' },
  { id: 'sat_rw_b7_105', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The architect\'s designs were characterized by a ________ elegance, achieving visual impact through clean lines and minimal ornamentation rather than through elaborate decoration.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'restrained' }, { letter: 'B', text: 'flamboyant' }, { letter: 'C', text: 'chaotic' }, { letter: 'D', text: 'ostentatious' }], correct: 'A', explanation: '"Restrained" means understated and controlled, fitting designs that use clean lines and minimal ornamentation.' },
  { id: 'sat_rw_b7_106', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The ecologist described the wetland as a ________ ecosystem, noting that the interdependence of its plant and animal species made it extremely vulnerable to disturbance.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'fragile' }, { letter: 'B', text: 'resilient' }, { letter: 'C', text: 'stagnant' }, { letter: 'D', text: 'isolated' }], correct: 'A', explanation: '"Fragile" means easily broken or damaged, fitting an ecosystem described as "extremely vulnerable to disturbance."' },
  { id: 'sat_rw_b7_107', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Literary scholar Edward Said\'s concept of "Orientalism" examines how Western scholarship and art have historically depicted Eastern societies as exotic, irrational, and fundamentally different from the West. Said argued that these representations were not merely inaccurate but served a political function, justifying Western colonial domination by constructing the East as inferior and in need of Western guidance. His work has influenced not only literary criticism but also fields such as anthropology, history, and political science.', question: 'According to Said\'s argument as presented in the passage, Western depictions of the East were significant because they:', options: [{ letter: 'A', text: 'provided ideological support for colonial power by characterizing Eastern societies as inferior' }, { letter: 'B', text: 'accurately represented the cultural differences between East and West' }, { letter: 'C', text: 'encouraged mutual understanding and respect between different civilizations' }, { letter: 'D', text: 'were limited to the field of literary criticism and had no political impact' }], correct: 'A', explanation: 'The passage states these representations served a "political function, justifying Western colonial domination."' },
  { id: 'sat_rw_b7_108', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The novelist\'s work is ________ in its scope, weaving together personal narratives with broader historical and philosophical themes to create a tapestry that encompasses the full range of human experience.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'capacious' }, { letter: 'B', text: 'parochial' }, { letter: 'C', text: 'reductive' }, { letter: 'D', text: 'insular' }], correct: 'A', explanation: '"Capacious" means having a lot of space or able to hold much, fitting work that encompasses the "full range of human experience."' },
  { id: 'sat_rw_b7_109', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The investigative report was ________, systematically dismantling the corporation\'s public relations narrative by presenting documented evidence of environmental violations.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'devastating' }, { letter: 'B', text: 'flattering' }, { letter: 'C', text: 'inconclusive' }, { letter: 'D', text: 'sympathetic' }], correct: 'A', explanation: '"Devastating" means highly destructive or damaging, fitting a report that systematically dismantles a corporation\'s narrative.' },
  { id: 'sat_rw_b7_110', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Behavioral ecologists have discovered that some species of birds engage in "mobbing" behavior, in which smaller birds collectively harass a larger predator such as a hawk or owl. While this behavior puts individual birds at risk, it appears to benefit the group by driving the predator away from nesting areas. The phenomenon has led researchers to reconsider the role of cooperative behavior in species traditionally thought to be primarily competitive.', question: 'The passage suggests that mobbing behavior is noteworthy because it:', options: [{ letter: 'A', text: 'challenges assumptions about competition by demonstrating cooperation in species previously thought to be competitive' }, { letter: 'B', text: 'proves that all bird species are fundamentally cooperative rather than competitive' }, { letter: 'C', text: 'shows that predators always flee when confronted by smaller birds' }, { letter: 'D', text: 'demonstrates that individual risk-taking never benefits the group' }], correct: 'A', explanation: 'The passage states mobbing has led researchers to "reconsider the role of cooperative behavior in species traditionally thought to be primarily competitive."' },
  { id: 'sat_rw_b7_111', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The philosopher maintained that moral principles should be ________, applying equally to all people regardless of their social status, cultural background, or personal circumstances.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'universal' }, { letter: 'B', text: 'arbitrary' }, { letter: 'C', text: 'conditional' }, { letter: 'D', text: 'subjective' }], correct: 'A', explanation: '"Universal" means applying to all cases, fitting moral principles that apply equally to everyone.' },
  { id: 'sat_rw_b7_112', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The writer\'s autobiographical novel was praised for its ________, offering an unflinchingly honest account of addiction and recovery that avoided both self-pity and self-aggrandizement.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'verisimilitude' }, { letter: 'B', text: 'hyperbole' }, { letter: 'C', text: 'obscurity' }, { letter: 'D', text: 'sentimentality' }], correct: 'A', explanation: '"Verisimilitude" means the appearance of being true or real, fitting an honest account that avoids distortion.' },
  { id: 'sat_rw_b7_113', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The concept of "code-switching" in sociolinguistics refers to the practice of alternating between two or more languages or language varieties within a single conversation. Far from indicating linguistic confusion, code-switching is a sophisticated communicative strategy that speakers use to signal social identity, establish solidarity, or convey nuanced meanings that may not be easily expressed in a single language. Research has shown that bilingual code-switchers demonstrate high levels of linguistic competence in both languages.', question: 'The passage\'s characterization of code-switching primarily serves to:', options: [{ letter: 'A', text: 'counter the misconception that code-switching reflects a deficiency in language ability' }, { letter: 'B', text: 'argue that monolingualism is superior to bilingualism' }, { letter: 'C', text: 'explain why code-switching is declining in multilingual communities' }, { letter: 'D', text: 'demonstrate that code-switching occurs only in formal settings' }], correct: 'A', explanation: 'The passage explicitly states code-switching is "far from indicating linguistic confusion" and shows "high levels of linguistic competence."' },
  { id: 'sat_rw_b7_114', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The curator described the artist\'s late period as one of ________ experimentation, during which she abandoned the representational techniques of her earlier career and embraced pure abstraction.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'radical' }, { letter: 'B', text: 'conservative' }, { letter: 'C', text: 'tentative' }, { letter: 'D', text: 'derivative' }], correct: 'A', explanation: '"Radical" means representing a complete change or departure, fitting the abandonment of representational techniques for abstraction.' },
  { id: 'sat_rw_b7_115', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'Confirmation bias, the tendency to seek out and favor information that confirms one\'s preexisting beliefs, poses a significant challenge to objective reasoning. Studies have shown that even when presented with balanced evidence, people tend to interpret ambiguous information in ways that support their existing views. This bias is not limited to laypeople; research scientists, despite their training in objective methodology, have been shown to exhibit confirmation bias when evaluating studies related to their own hypotheses.', question: 'The author mentions research scientists in the passage most likely in order to:', options: [{ letter: 'A', text: 'emphasize that confirmation bias affects even those trained to be objective' }, { letter: 'B', text: 'argue that scientific research is fundamentally unreliable' }, { letter: 'C', text: 'suggest that scientists are more susceptible to bias than the general public' }, { letter: 'D', text: 'propose that scientific training should be reformed to eliminate all bias' }], correct: 'A', explanation: 'Mentioning scientists demonstrates the pervasiveness of confirmation bias by showing it affects even trained objective thinkers.' },
  { id: 'sat_rw_b7_116', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The political theorist argued that the regime\'s stability was ________, maintained only through censorship and surveillance rather than genuine popular support.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'illusory' }, { letter: 'B', text: 'legitimate' }, { letter: 'C', text: 'robust' }, { letter: 'D', text: 'democratic' }], correct: 'A', explanation: '"Illusory" means based on illusion or not real, fitting stability maintained by force rather than genuine support.' },
  { id: 'sat_rw_b7_117', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The scholar\'s interpretation of the ancient text was ________, drawing connections between the manuscript and contemporary philosophical debates that other researchers had overlooked.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'perspicacious' }, { letter: 'B', text: 'pedestrian' }, { letter: 'C', text: 'derivative' }, { letter: 'D', text: 'superficial' }], correct: 'A', explanation: '"Perspicacious" means having keen mental perception and insight, fitting a scholar who draws connections others missed.' },
  { id: 'sat_rw_b7_118', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The "replication crisis" in psychology refers to the finding that many landmark studies in the field cannot be replicated when other researchers attempt to reproduce their results. A large-scale effort in 2015 attempted to replicate 100 published psychology studies and found that only about one-third produced similar results. While some argue this indicates fundamental problems with research methodology, others contend that failed replications may result from subtle differences in experimental conditions rather than flaws in the original studies.', question: 'The passage presents the replication crisis as:', options: [{ letter: 'A', text: 'a significant concern whose causes are still debated among researchers' }, { letter: 'B', text: 'a problem that has been fully resolved by improvements in research methods' }, { letter: 'C', text: 'evidence that psychology should not be considered a legitimate science' }, { letter: 'D', text: 'a minor issue that affects only a small number of studies' }], correct: 'A', explanation: 'The passage describes the crisis as significant (only one-third replicated) and presents two competing explanations, indicating ongoing debate.' },
  { id: 'sat_rw_b7_119', category: 'reading', subcategory: 'vocabulary', difficulty: 'hard', passage: 'The philosopher contended that the apparent ________ between free will and determinism could be resolved by reconceptualizing both concepts, arguing that they are not mutually exclusive but rather complementary aspects of human experience.', question: 'Which choice completes the text with the most logical and precise word?', options: [{ letter: 'A', text: 'antinomy' }, { letter: 'B', text: 'synthesis' }, { letter: 'C', text: 'equivalence' }, { letter: 'D', text: 'collaboration' }], correct: 'A', explanation: '"Antinomy" means a contradiction between two beliefs that are both reasonable, fitting the apparent conflict between free will and determinism.' },
  { id: 'sat_rw_b7_120', category: 'reading', subcategory: 'reading-comprehension', difficulty: 'hard', passage: 'The "overview effect" is a cognitive shift reported by astronauts who have viewed Earth from space. Many describe experiencing a profound sense of interconnectedness and a diminished perception of national borders and conflicts. Astronaut Edgar Mitchell described it as an "instant global consciousness." Some researchers have proposed using virtual reality simulations of the experience to foster greater environmental awareness and international cooperation, though critics question whether a simulated experience can produce the same psychological impact as the real thing.', question: 'The critics mentioned in the passage would most likely argue that:', options: [{ letter: 'A', text: 'virtual reality cannot fully replicate the psychological effects of actually viewing Earth from space' }, { letter: 'B', text: 'the overview effect has never been experienced by any astronaut' }, { letter: 'C', text: 'environmental awareness cannot be increased through any technological means' }, { letter: 'D', text: 'virtual reality simulations are too expensive to be practical' }], correct: 'A', explanation: 'The critics "question whether a simulated experience can produce the same psychological impact as the real thing."' }
];
